import{i as e,r as t,s as n,t as r}from"./app-B1jqjtqq.js";var i=JSON.parse(`{"path":"/java-tutor/orm-tutor/pgsql/query-advanced.html","title":"PostgreSQL 高级查询","lang":"zh-CN","frontmatter":{"description":"PostgreSQL 高级查询 窗口函数、CTE 公用表表达式、JSON 操作、全文检索等高级特性。 窗口函数（Window Functions） 窗口函数在不改变行数的情况下对行集进行计算，与聚合函数不同，它不会合并行。 基础语法 ROW_NUMBER / RANK / DENSE_RANK 聚合窗口函数 LEAD / LAG FIRST_VALUE...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"PostgreSQL 高级查询\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-07-13T07:23:11.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"yzqdev\\",\\"url\\":\\"http://www.yzqdev.top\\"}]}"],["meta",{"property":"og:url","content":"https://yzqdev.github.io/cs-guide/cs-guide/java-tutor/orm-tutor/pgsql/query-advanced.html"}],["meta",{"property":"og:site_name","content":"cs-guide"}],["meta",{"property":"og:title","content":"PostgreSQL 高级查询"}],["meta",{"property":"og:description","content":"PostgreSQL 高级查询 窗口函数、CTE 公用表表达式、JSON 操作、全文检索等高级特性。 窗口函数（Window Functions） 窗口函数在不改变行数的情况下对行集进行计算，与聚合函数不同，它不会合并行。 基础语法 ROW_NUMBER / RANK / DENSE_RANK 聚合窗口函数 LEAD / LAG FIRST_VALUE..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-07-13T07:23:11.000Z"}],["meta",{"property":"article:modified_time","content":"2026-07-13T07:23:11.000Z"}]]},"git":{"createdTime":1783927391000,"updatedTime":1783927391000,"contributors":[{"name":"yzqdev","username":"yzqdev","email":"yzqdev@outlook.com","commits":1,"url":"https://github.com/yzqdev"}]},"readingTime":{"minutes":4.8,"words":1441},"filePathRelative":"java-tutor/orm-tutor/pgsql/query-advanced.md","autoDesc":true}`),a={name:`query-advanced.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="postgresql-高级查询" tabindex="-1"><a class="header-anchor" href="#postgresql-高级查询"><span>PostgreSQL 高级查询</span></a></h1><blockquote><p>窗口函数、CTE 公用表表达式、JSON 操作、全文检索等高级特性。</p></blockquote><h2 id="窗口函数-window-functions" tabindex="-1"><a class="header-anchor" href="#窗口函数-window-functions"><span>窗口函数（Window Functions）</span></a></h2><p>窗口函数在不改变行数的情况下对行集进行计算，与聚合函数不同，它不会合并行。</p><h3 id="基础语法" tabindex="-1"><a class="header-anchor" href="#基础语法"><span>基础语法</span></a></h3><div class="language-sql" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token keyword">SELECT</span> 字段<span class="token punctuation">,</span></span>
<span class="line">       窗口函数<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span></span>
<span class="line">           <span class="token keyword">PARTITION</span> <span class="token keyword">BY</span> 分组字段</span>
<span class="line">           <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> 排序字段</span>
<span class="line">           <span class="token keyword">ROWS</span><span class="token operator">/</span>RANGE <span class="token operator">BETWEEN</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token operator">AND</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line">       <span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">FROM</span> 表<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre></div><h3 id="row-number-rank-dense-rank" tabindex="-1"><a class="header-anchor" href="#row-number-rank-dense-rank"><span>ROW_NUMBER / RANK / DENSE_RANK</span></a></h3><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> scores <span class="token punctuation">(</span></span>
<span class="line">    id <span class="token keyword">SERIAL</span> <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">,</span></span>
<span class="line">    student_name <span class="token keyword">TEXT</span><span class="token punctuation">,</span></span>
<span class="line">    subject <span class="token keyword">TEXT</span><span class="token punctuation">,</span></span>
<span class="line">    score <span class="token keyword">INT</span></span>
<span class="line"><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> scores <span class="token keyword">VALUES</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&#39;张三&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;语文&#39;</span><span class="token punctuation">,</span> <span class="token number">85</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;李四&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;语文&#39;</span><span class="token punctuation">,</span> <span class="token number">92</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">,</span> <span class="token string">&#39;王五&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;语文&#39;</span><span class="token punctuation">,</span> <span class="token number">85</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">,</span> <span class="token string">&#39;张三&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;数学&#39;</span><span class="token punctuation">,</span> <span class="token number">90</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">,</span> <span class="token string">&#39;李四&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;数学&#39;</span><span class="token punctuation">,</span> <span class="token number">95</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">6</span><span class="token punctuation">,</span> <span class="token string">&#39;王五&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;数学&#39;</span><span class="token punctuation">,</span> <span class="token number">88</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 每个学科的排名</span></span>
<span class="line"><span class="token keyword">SELECT</span></span>
<span class="line">    student_name<span class="token punctuation">,</span></span>
<span class="line">    subject<span class="token punctuation">,</span></span>
<span class="line">    score<span class="token punctuation">,</span></span>
<span class="line">    ROW_NUMBER<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">PARTITION</span> <span class="token keyword">BY</span> subject <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> score <span class="token keyword">DESC</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> row_num<span class="token punctuation">,</span></span>
<span class="line">    RANK<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">PARTITION</span> <span class="token keyword">BY</span> subject <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> score <span class="token keyword">DESC</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> rank<span class="token punctuation">,</span></span>
<span class="line">    DENSE_RANK<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">PARTITION</span> <span class="token keyword">BY</span> subject <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> score <span class="token keyword">DESC</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> dense_rank</span>
<span class="line"><span class="token keyword">FROM</span> scores<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 结果：</span></span>
<span class="line"><span class="token comment">-- 李四  语文  92  1  1  1</span></span>
<span class="line"><span class="token comment">-- 张三  语文  85  2  2  2</span></span>
<span class="line"><span class="token comment">-- 王五  语文  85  3  2  2  (RANK 并列，DENSE_RANK 不跳号)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="聚合窗口函数" tabindex="-1"><a class="header-anchor" href="#聚合窗口函数"><span>聚合窗口函数</span></a></h3><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 累计求和</span></span>
<span class="line"><span class="token keyword">SELECT</span></span>
<span class="line">    order_date<span class="token punctuation">,</span></span>
<span class="line">    amount<span class="token punctuation">,</span></span>
<span class="line">    <span class="token function">SUM</span><span class="token punctuation">(</span>amount<span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">ORDER</span> <span class="token keyword">BY</span> order_date<span class="token punctuation">)</span> <span class="token keyword">AS</span> cumulative_amount</span>
<span class="line"><span class="token keyword">FROM</span> orders<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 移动平均（最近 3 天）</span></span>
<span class="line"><span class="token keyword">SELECT</span></span>
<span class="line">    order_date<span class="token punctuation">,</span></span>
<span class="line">    amount<span class="token punctuation">,</span></span>
<span class="line">    <span class="token function">AVG</span><span class="token punctuation">(</span>amount<span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">ORDER</span> <span class="token keyword">BY</span> order_date <span class="token keyword">ROWS</span> <span class="token operator">BETWEEN</span> <span class="token number">2</span> <span class="token keyword">PRECEDING</span> <span class="token operator">AND</span> <span class="token keyword">CURRENT</span> <span class="token keyword">ROW</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> moving_avg</span>
<span class="line"><span class="token keyword">FROM</span> orders<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 分组内占比</span></span>
<span class="line"><span class="token keyword">SELECT</span></span>
<span class="line">    department<span class="token punctuation">,</span></span>
<span class="line">    employee_name<span class="token punctuation">,</span></span>
<span class="line">    salary<span class="token punctuation">,</span></span>
<span class="line">    <span class="token function">ROUND</span><span class="token punctuation">(</span>salary <span class="token operator">/</span> <span class="token function">SUM</span><span class="token punctuation">(</span>salary<span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">PARTITION</span> <span class="token keyword">BY</span> department<span class="token punctuation">)</span> <span class="token operator">*</span> <span class="token number">100</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> pct</span>
<span class="line"><span class="token keyword">FROM</span> employees<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="lead-lag" tabindex="-1"><a class="header-anchor" href="#lead-lag"><span>LEAD / LAG</span></a></h3><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 获取前后行的值</span></span>
<span class="line"><span class="token keyword">SELECT</span></span>
<span class="line">    order_date<span class="token punctuation">,</span></span>
<span class="line">    amount<span class="token punctuation">,</span></span>
<span class="line">    LAG<span class="token punctuation">(</span>amount<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">ORDER</span> <span class="token keyword">BY</span> order_date<span class="token punctuation">)</span> <span class="token keyword">AS</span> prev_amount<span class="token punctuation">,</span>  <span class="token comment">-- 前一天</span></span>
<span class="line">    LEAD<span class="token punctuation">(</span>amount<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">ORDER</span> <span class="token keyword">BY</span> order_date<span class="token punctuation">)</span> <span class="token keyword">AS</span> next_amount  <span class="token comment">-- 后一天</span></span>
<span class="line"><span class="token keyword">FROM</span> orders<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 计算环比增长</span></span>
<span class="line"><span class="token keyword">SELECT</span></span>
<span class="line">    order_date<span class="token punctuation">,</span></span>
<span class="line">    amount<span class="token punctuation">,</span></span>
<span class="line">    LAG<span class="token punctuation">(</span>amount<span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">ORDER</span> <span class="token keyword">BY</span> order_date<span class="token punctuation">)</span> <span class="token keyword">AS</span> prev_amount<span class="token punctuation">,</span></span>
<span class="line">    <span class="token keyword">CASE</span></span>
<span class="line">        <span class="token keyword">WHEN</span> LAG<span class="token punctuation">(</span>amount<span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">ORDER</span> <span class="token keyword">BY</span> order_date<span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">0</span> <span class="token keyword">THEN</span> <span class="token boolean">NULL</span></span>
<span class="line">        <span class="token keyword">ELSE</span> <span class="token function">ROUND</span><span class="token punctuation">(</span><span class="token punctuation">(</span>amount <span class="token operator">-</span> LAG<span class="token punctuation">(</span>amount<span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">ORDER</span> <span class="token keyword">BY</span> order_date<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">/</span></span>
<span class="line">             LAG<span class="token punctuation">(</span>amount<span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">ORDER</span> <span class="token keyword">BY</span> order_date<span class="token punctuation">)</span> <span class="token operator">*</span> <span class="token number">100</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">END</span> <span class="token keyword">AS</span> growth_rate</span>
<span class="line"><span class="token keyword">FROM</span> orders<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="first-value-last-value" tabindex="-1"><a class="header-anchor" href="#first-value-last-value"><span>FIRST_VALUE / LAST_VALUE</span></a></h3><div class="language-sql" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 分组内的第一个和最后一个值</span></span>
<span class="line"><span class="token keyword">SELECT</span></span>
<span class="line">    department<span class="token punctuation">,</span></span>
<span class="line">    employee_name<span class="token punctuation">,</span></span>
<span class="line">    salary<span class="token punctuation">,</span></span>
<span class="line">    FIRST_VALUE<span class="token punctuation">(</span>employee_name<span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">PARTITION</span> <span class="token keyword">BY</span> department <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> salary <span class="token keyword">DESC</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> highest_paid<span class="token punctuation">,</span></span>
<span class="line">    LAST_VALUE<span class="token punctuation">(</span>employee_name<span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span></span>
<span class="line">        <span class="token keyword">PARTITION</span> <span class="token keyword">BY</span> department</span>
<span class="line">        <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> salary <span class="token keyword">DESC</span></span>
<span class="line">        RANGE <span class="token operator">BETWEEN</span> <span class="token keyword">UNBOUNDED</span> <span class="token keyword">PRECEDING</span> <span class="token operator">AND</span> <span class="token keyword">UNBOUNDED</span> <span class="token keyword">FOLLOWING</span></span>
<span class="line">    <span class="token punctuation">)</span> <span class="token keyword">AS</span> lowest_paid</span>
<span class="line"><span class="token keyword">FROM</span> employees<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre></div><h3 id="ntile-—-分桶" tabindex="-1"><a class="header-anchor" href="#ntile-—-分桶"><span>NTILE — 分桶</span></a></h3><div class="language-sql" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 将数据分成 N 组</span></span>
<span class="line"><span class="token keyword">SELECT</span></span>
<span class="line">    student_name<span class="token punctuation">,</span></span>
<span class="line">    score<span class="token punctuation">,</span></span>
<span class="line">    NTILE<span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">ORDER</span> <span class="token keyword">BY</span> score <span class="token keyword">DESC</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> quartile  <span class="token comment">-- 四分位</span></span>
<span class="line"><span class="token keyword">FROM</span> scores<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre></div><h2 id="cte-公用表表达式-with" tabindex="-1"><a class="header-anchor" href="#cte-公用表表达式-with"><span>CTE 公用表表达式（WITH）</span></a></h2><p>CTE 让复杂查询更清晰，也支持递归。</p><h3 id="基本-cte" tabindex="-1"><a class="header-anchor" href="#基本-cte"><span>基本 CTE</span></a></h3><div class="language-sql" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 用 CTE 分解复杂查询</span></span>
<span class="line"><span class="token keyword">WITH</span> high_scores <span class="token keyword">AS</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> scores <span class="token keyword">WHERE</span> score <span class="token operator">&gt;=</span> <span class="token number">90</span></span>
<span class="line"><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">student_count <span class="token keyword">AS</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token keyword">SELECT</span> <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> cnt <span class="token keyword">FROM</span> scores</span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">SELECT</span> h<span class="token punctuation">.</span><span class="token operator">*</span><span class="token punctuation">,</span> s<span class="token punctuation">.</span>cnt</span>
<span class="line"><span class="token keyword">FROM</span> high_scores h<span class="token punctuation">,</span> student_count s<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 相当于临时视图，只在当前查询中有效</span></span>
<span class="line"></span></code></pre></div><h3 id="多表-cte" tabindex="-1"><a class="header-anchor" href="#多表-cte"><span>多表 CTE</span></a></h3><div class="language-sql" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 找出每个学科最高分的学生</span></span>
<span class="line"><span class="token keyword">WITH</span> max_scores <span class="token keyword">AS</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token keyword">SELECT</span> subject<span class="token punctuation">,</span> <span class="token function">MAX</span><span class="token punctuation">(</span>score<span class="token punctuation">)</span> <span class="token keyword">AS</span> max_score</span>
<span class="line">    <span class="token keyword">FROM</span> scores</span>
<span class="line">    <span class="token keyword">GROUP</span> <span class="token keyword">BY</span> subject</span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">SELECT</span> s<span class="token punctuation">.</span>student_name<span class="token punctuation">,</span> s<span class="token punctuation">.</span>subject<span class="token punctuation">,</span> s<span class="token punctuation">.</span>score</span>
<span class="line"><span class="token keyword">FROM</span> scores s</span>
<span class="line"><span class="token keyword">JOIN</span> max_scores m <span class="token keyword">ON</span> s<span class="token punctuation">.</span>subject <span class="token operator">=</span> m<span class="token punctuation">.</span>subject <span class="token operator">AND</span> s<span class="token punctuation">.</span>score <span class="token operator">=</span> m<span class="token punctuation">.</span>max_score<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre></div><h3 id="递归-cte" tabindex="-1"><a class="header-anchor" href="#递归-cte"><span>递归 CTE</span></a></h3><p>递归 CTE 用于处理树形结构数据（如组织架构、评论回复）。</p><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 创建分类表（树形结构）</span></span>
<span class="line"><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> categories <span class="token punctuation">(</span></span>
<span class="line">    id <span class="token keyword">SERIAL</span> <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">,</span></span>
<span class="line">    name <span class="token keyword">TEXT</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span><span class="token punctuation">,</span></span>
<span class="line">    parent_id <span class="token keyword">INT</span> <span class="token keyword">REFERENCES</span> categories<span class="token punctuation">(</span>id<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> categories <span class="token keyword">VALUES</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&#39;电子产品&#39;</span><span class="token punctuation">,</span> <span class="token boolean">NULL</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;手机&#39;</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">,</span> <span class="token string">&#39;电脑&#39;</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">,</span> <span class="token string">&#39;智能手机&#39;</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">,</span> <span class="token string">&#39;功能手机&#39;</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">6</span><span class="token punctuation">,</span> <span class="token string">&#39;笔记本&#39;</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">7</span><span class="token punctuation">,</span> <span class="token string">&#39;台式机&#39;</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 递归查询所有子分类</span></span>
<span class="line"><span class="token keyword">WITH</span> RECURSIVE category_tree <span class="token keyword">AS</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token comment">-- 基础情况：顶级分类</span></span>
<span class="line">    <span class="token keyword">SELECT</span> id<span class="token punctuation">,</span> name<span class="token punctuation">,</span> parent_id<span class="token punctuation">,</span> <span class="token number">0</span> <span class="token keyword">AS</span> <span class="token keyword">level</span></span>
<span class="line">    <span class="token keyword">FROM</span> categories</span>
<span class="line">    <span class="token keyword">WHERE</span> parent_id <span class="token operator">IS</span> <span class="token boolean">NULL</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">UNION</span> <span class="token keyword">ALL</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">-- 递归：子分类</span></span>
<span class="line">    <span class="token keyword">SELECT</span> c<span class="token punctuation">.</span>id<span class="token punctuation">,</span> c<span class="token punctuation">.</span>name<span class="token punctuation">,</span> c<span class="token punctuation">.</span>parent_id<span class="token punctuation">,</span> ct<span class="token punctuation">.</span><span class="token keyword">level</span> <span class="token operator">+</span> <span class="token number">1</span></span>
<span class="line">    <span class="token keyword">FROM</span> categories c</span>
<span class="line">    <span class="token keyword">JOIN</span> category_tree ct <span class="token keyword">ON</span> c<span class="token punctuation">.</span>parent_id <span class="token operator">=</span> ct<span class="token punctuation">.</span>id</span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> category_tree <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> <span class="token keyword">level</span><span class="token punctuation">,</span> id<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 结果：</span></span>
<span class="line"><span class="token comment">-- 1  电子产品     NULL  0</span></span>
<span class="line"><span class="token comment">-- 2  手机        1     1</span></span>
<span class="line"><span class="token comment">-- 3  电脑        1     1</span></span>
<span class="line"><span class="token comment">-- 4  智能手机    2     2</span></span>
<span class="line"><span class="token comment">-- 5  功能手机    2     2</span></span>
<span class="line"><span class="token comment">-- 6  笔记本      3     2</span></span>
<span class="line"><span class="token comment">-- 7  台式机      3     2</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="递归查询组织架构" tabindex="-1"><a class="header-anchor" href="#递归查询组织架构"><span>递归查询组织架构</span></a></h3><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> employees <span class="token punctuation">(</span></span>
<span class="line">    id <span class="token keyword">SERIAL</span> <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">,</span></span>
<span class="line">    name <span class="token keyword">TEXT</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span><span class="token punctuation">,</span></span>
<span class="line">    manager_id <span class="token keyword">INT</span> <span class="token keyword">REFERENCES</span> employees<span class="token punctuation">(</span>id<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> employees <span class="token keyword">VALUES</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&#39;CEO&#39;</span><span class="token punctuation">,</span> <span class="token boolean">NULL</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;CTO&#39;</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">,</span> <span class="token string">&#39;CFO&#39;</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">,</span> <span class="token string">&#39;高级工程师&#39;</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">,</span> <span class="token string">&#39;初级工程师&#39;</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">WITH</span> RECURSIVE org_chart <span class="token keyword">AS</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token keyword">SELECT</span> id<span class="token punctuation">,</span> name<span class="token punctuation">,</span> manager_id<span class="token punctuation">,</span> <span class="token number">0</span> <span class="token keyword">AS</span> <span class="token keyword">level</span><span class="token punctuation">,</span> name <span class="token keyword">AS</span> path</span>
<span class="line">    <span class="token keyword">FROM</span> employees <span class="token keyword">WHERE</span> manager_id <span class="token operator">IS</span> <span class="token boolean">NULL</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">UNION</span> <span class="token keyword">ALL</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">SELECT</span> e<span class="token punctuation">.</span>id<span class="token punctuation">,</span> e<span class="token punctuation">.</span>name<span class="token punctuation">,</span> e<span class="token punctuation">.</span>manager_id<span class="token punctuation">,</span> oc<span class="token punctuation">.</span><span class="token keyword">level</span> <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">,</span></span>
<span class="line">           oc<span class="token punctuation">.</span>path <span class="token operator">||</span> <span class="token string">&#39; -&gt; &#39;</span> <span class="token operator">||</span> e<span class="token punctuation">.</span>name</span>
<span class="line">    <span class="token keyword">FROM</span> employees e</span>
<span class="line">    <span class="token keyword">JOIN</span> org_chart oc <span class="token keyword">ON</span> e<span class="token punctuation">.</span>manager_id <span class="token operator">=</span> oc<span class="token punctuation">.</span>id</span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> org_chart <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> <span class="token keyword">level</span><span class="token punctuation">,</span> id<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="json-高级操作" tabindex="-1"><a class="header-anchor" href="#json-高级操作"><span>JSON 高级操作</span></a></h2><h3 id="json-查询" tabindex="-1"><a class="header-anchor" href="#json-查询"><span>JSON 查询</span></a></h3><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 创建表</span></span>
<span class="line"><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> products <span class="token punctuation">(</span></span>
<span class="line">    id <span class="token keyword">SERIAL</span> <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token keyword">data</span> JSONB</span>
<span class="line"><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> products <span class="token punctuation">(</span><span class="token keyword">data</span><span class="token punctuation">)</span> <span class="token keyword">VALUES</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token string">&#39;{&quot;name&quot;: &quot;手机&quot;, &quot;price&quot;: 4999, &quot;specs&quot;: {&quot;ram&quot;: &quot;8GB&quot;, &quot;rom&quot;: &quot;128GB&quot;}, &quot;tags&quot;: [&quot;电子&quot;, &quot;通信&quot;]}&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token string">&#39;{&quot;name&quot;: &quot;电脑&quot;, &quot;price&quot;: 12999, &quot;specs&quot;: {&quot;ram&quot;: &quot;16GB&quot;, &quot;rom&quot;: &quot;512GB&quot;}, &quot;tags&quot;: [&quot;电子&quot;, &quot;办公&quot;]}&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 基本查询</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">data</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token string">&#39;name&#39;</span> <span class="token keyword">AS</span> name <span class="token keyword">FROM</span> products<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">data</span> <span class="token operator">-</span><span class="token operator">&gt;&gt;</span> <span class="token string">&#39;name&#39;</span> <span class="token keyword">AS</span> name <span class="token keyword">FROM</span> products<span class="token punctuation">;</span>  <span class="token comment">-- 去引号</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 嵌套 JSON</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">data</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token string">&#39;specs&#39;</span> <span class="token operator">-</span><span class="token operator">&gt;&gt;</span> <span class="token string">&#39;ram&#39;</span> <span class="token keyword">AS</span> ram <span class="token keyword">FROM</span> products<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- WHERE 条件</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> products <span class="token keyword">WHERE</span> <span class="token keyword">data</span> @<span class="token operator">&gt;</span> <span class="token string">&#39;{&quot;name&quot;: &quot;手机&quot;}&#39;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> products <span class="token keyword">WHERE</span> <span class="token keyword">data</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token string">&#39;specs&#39;</span> <span class="token operator">-</span><span class="token operator">&gt;&gt;</span> <span class="token string">&#39;ram&#39;</span> <span class="token operator">=</span> <span class="token string">&#39;8GB&#39;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- JSON 路径查询（PostgreSQL 12+）</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">data</span> @? <span class="token string">&#39;$.specs.ram&#39;</span> <span class="token keyword">FROM</span> products<span class="token punctuation">;</span>  <span class="token comment">-- 是否存在路径</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">data</span> @@ <span class="token string">&#39;$.price &gt; 5000&#39;</span> <span class="token keyword">FROM</span> products<span class="token punctuation">;</span>  <span class="token comment">-- 路径表达式</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="json-修改" tabindex="-1"><a class="header-anchor" href="#json-修改"><span>JSON 修改</span></a></h3><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 更新 JSON 字段</span></span>
<span class="line"><span class="token keyword">UPDATE</span> products</span>
<span class="line"><span class="token keyword">SET</span> <span class="token keyword">data</span> <span class="token operator">=</span> jsonb_set<span class="token punctuation">(</span><span class="token keyword">data</span><span class="token punctuation">,</span> <span class="token string">&#39;{price}&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;5999&#39;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">WHERE</span> <span class="token keyword">data</span> <span class="token operator">-</span><span class="token operator">&gt;&gt;</span> <span class="token string">&#39;name&#39;</span> <span class="token operator">=</span> <span class="token string">&#39;手机&#39;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 删除 JSON 字段</span></span>
<span class="line"><span class="token keyword">UPDATE</span> products</span>
<span class="line"><span class="token keyword">SET</span> <span class="token keyword">data</span> <span class="token operator">=</span> <span class="token keyword">data</span> <span class="token operator">-</span> <span class="token string">&#39;tags&#39;</span></span>
<span class="line"><span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- JSON 拼接</span></span>
<span class="line"><span class="token keyword">UPDATE</span> products</span>
<span class="line"><span class="token keyword">SET</span> <span class="token keyword">data</span> <span class="token operator">=</span> <span class="token keyword">data</span> <span class="token operator">||</span> <span class="token string">&#39;{&quot;warranty&quot;: &quot;1 year&quot;}&#39;</span>::jsonb<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- JSON 数组追加</span></span>
<span class="line"><span class="token keyword">UPDATE</span> products</span>
<span class="line"><span class="token keyword">SET</span> <span class="token keyword">data</span> <span class="token operator">=</span> jsonb_set<span class="token punctuation">(</span><span class="token keyword">data</span><span class="token punctuation">,</span> <span class="token string">&#39;{tags}&#39;</span><span class="token punctuation">,</span> <span class="token keyword">data</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token string">&#39;tags&#39;</span> <span class="token operator">||</span> <span class="token string">&#39;&quot;新品&quot;&#39;</span>::jsonb<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="json-聚合" tabindex="-1"><a class="header-anchor" href="#json-聚合"><span>JSON 聚合</span></a></h3><div class="language-sql" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 行转 JSON 数组</span></span>
<span class="line"><span class="token keyword">SELECT</span> jsonb_agg<span class="token punctuation">(</span><span class="token keyword">data</span><span class="token punctuation">)</span> <span class="token keyword">FROM</span> products<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 行转 JSON 对象</span></span>
<span class="line"><span class="token keyword">SELECT</span> jsonb_object_agg<span class="token punctuation">(</span><span class="token keyword">data</span> <span class="token operator">-</span><span class="token operator">&gt;&gt;</span> <span class="token string">&#39;name&#39;</span><span class="token punctuation">,</span> <span class="token keyword">data</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token string">&#39;price&#39;</span><span class="token punctuation">)</span> <span class="token keyword">FROM</span> products<span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">-- {&quot;手机&quot;: 4999, &quot;电脑&quot;: 12999}</span></span>
<span class="line"></span></code></pre></div><h2 id="全文检索" tabindex="-1"><a class="header-anchor" href="#全文检索"><span>全文检索</span></a></h2><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 创建表</span></span>
<span class="line"><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> articles <span class="token punctuation">(</span></span>
<span class="line">    id <span class="token keyword">SERIAL</span> <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">,</span></span>
<span class="line">    title <span class="token keyword">TEXT</span><span class="token punctuation">,</span></span>
<span class="line">    body <span class="token keyword">TEXT</span><span class="token punctuation">,</span></span>
<span class="line">    search_vector TSVECTOR</span>
<span class="line"><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 插入数据</span></span>
<span class="line"><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> articles <span class="token punctuation">(</span>title<span class="token punctuation">,</span> body<span class="token punctuation">)</span> <span class="token keyword">VALUES</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token string">&#39;PostgreSQL 教程&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;PostgreSQL 是一个功能强大的开源数据库&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token string">&#39;Java 编程&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;Java 是一种面向对象的编程语言&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token string">&#39;数据库设计&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;好的数据库设计是系统成功的关键&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 更新全文检索向量</span></span>
<span class="line"><span class="token keyword">UPDATE</span> articles <span class="token keyword">SET</span></span>
<span class="line">search_vector <span class="token operator">=</span> to_tsvector<span class="token punctuation">(</span><span class="token string">&#39;simple&#39;</span><span class="token punctuation">,</span> <span class="token keyword">coalesce</span><span class="token punctuation">(</span>title<span class="token punctuation">,</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">)</span> <span class="token operator">||</span> <span class="token string">&#39; &#39;</span> <span class="token operator">||</span> <span class="token keyword">coalesce</span><span class="token punctuation">(</span>body<span class="token punctuation">,</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 创建 GIN 索引</span></span>
<span class="line"><span class="token keyword">CREATE</span> <span class="token keyword">INDEX</span> idx_articles_search <span class="token keyword">ON</span> articles <span class="token keyword">USING</span> GIN <span class="token punctuation">(</span>search_vector<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 全文检索查询</span></span>
<span class="line"><span class="token keyword">SELECT</span> title<span class="token punctuation">,</span> ts_headline<span class="token punctuation">(</span><span class="token string">&#39;simple&#39;</span><span class="token punctuation">,</span> body<span class="token punctuation">,</span> to_tsquery<span class="token punctuation">(</span><span class="token string">&#39;simple&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;数据库 &amp; 设计&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">FROM</span> articles</span>
<span class="line"><span class="token keyword">WHERE</span> search_vector @@ to_tsquery<span class="token punctuation">(</span><span class="token string">&#39;simple&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;数据库 &amp; 设计&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 高亮结果</span></span>
<span class="line"><span class="token keyword">SELECT</span> title<span class="token punctuation">,</span> ts_headline<span class="token punctuation">(</span>body<span class="token punctuation">,</span> to_tsquery<span class="token punctuation">(</span><span class="token string">&#39;simple&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;数据库&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">FROM</span> articles</span>
<span class="line"><span class="token keyword">WHERE</span> search_vector @@ to_tsquery<span class="token punctuation">(</span><span class="token string">&#39;simple&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;数据库&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="练习" tabindex="-1"><a class="header-anchor" href="#练习"><span>练习</span></a></h2><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 1. 使用窗口函数计算每个部门薪资排名前 3 的员工</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token keyword">SELECT</span></span>
<span class="line">        department<span class="token punctuation">,</span></span>
<span class="line">        employee_name<span class="token punctuation">,</span></span>
<span class="line">        salary<span class="token punctuation">,</span></span>
<span class="line">        DENSE_RANK<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">OVER</span> <span class="token punctuation">(</span><span class="token keyword">PARTITION</span> <span class="token keyword">BY</span> department <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> salary <span class="token keyword">DESC</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> rank</span>
<span class="line">    <span class="token keyword">FROM</span> employees</span>
<span class="line"><span class="token punctuation">)</span> ranked</span>
<span class="line"><span class="token keyword">WHERE</span> rank <span class="token operator">&lt;=</span> <span class="token number">3</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 2. 使用 CTE 查询组织架构树</span></span>
<span class="line"><span class="token keyword">WITH</span> RECURSIVE org_tree <span class="token keyword">AS</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token keyword">SELECT</span> id<span class="token punctuation">,</span> name<span class="token punctuation">,</span> manager_id<span class="token punctuation">,</span> <span class="token number">1</span> <span class="token keyword">AS</span> depth</span>
<span class="line">    <span class="token keyword">FROM</span> employees <span class="token keyword">WHERE</span> manager_id <span class="token operator">IS</span> <span class="token boolean">NULL</span></span>
<span class="line">    <span class="token keyword">UNION</span> <span class="token keyword">ALL</span></span>
<span class="line">    <span class="token keyword">SELECT</span> e<span class="token punctuation">.</span>id<span class="token punctuation">,</span> e<span class="token punctuation">.</span>name<span class="token punctuation">,</span> e<span class="token punctuation">.</span>manager_id<span class="token punctuation">,</span> ot<span class="token punctuation">.</span>depth <span class="token operator">+</span> <span class="token number">1</span></span>
<span class="line">    <span class="token keyword">FROM</span> employees e</span>
<span class="line">    <span class="token keyword">JOIN</span> org_tree ot <span class="token keyword">ON</span> e<span class="token punctuation">.</span>manager_id <span class="token operator">=</span> ot<span class="token punctuation">.</span>id</span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> org_tree <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> depth<span class="token punctuation">,</span> id<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 3. 查询 JSONB 中价格大于 5000 的商品</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">data</span> <span class="token operator">-</span><span class="token operator">&gt;&gt;</span> <span class="token string">&#39;name&#39;</span> <span class="token keyword">AS</span> name<span class="token punctuation">,</span> <span class="token keyword">data</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token string">&#39;price&#39;</span> <span class="token keyword">AS</span> price</span>
<span class="line"><span class="token keyword">FROM</span> products</span>
<span class="line"><span class="token keyword">WHERE</span> <span class="token punctuation">(</span><span class="token keyword">data</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token string">&#39;price&#39;</span><span class="token punctuation">)</span>::<span class="token keyword">numeric</span> <span class="token operator">&gt;</span> <span class="token number">5000</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,38)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};